'use client';

import React from 'react';
import { Card, Elevation, Spinner, Icon, IconName, H2, Classes } from '@blueprintjs/core';

interface KPICardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  icon?: IconName;
  loading?: boolean;
  tooltip?: string;
  onClick?: () => void;
}

/**
 * KPI Card Component
 *
 * Displays a single KPI metric with title, value, and optional subtitle.
 * Uses EN 15380 railway terminology.
 */
export function KPICard({
  title,
  value,
  subtitle,
  icon,
  loading = false,
  tooltip,
  onClick,
}: KPICardProps) {
  return (
    <Card
      elevation={Elevation.ONE}
      interactive={!!onClick}
      onClick={onClick}
      title={tooltip}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span className={Classes.TEXT_MUTED}>{title}</span>
        {icon && <Icon icon={icon} size={20} className={Classes.TEXT_MUTED} />}
      </div>
      <div>
        {loading ? (
          <Spinner size={24} />
        ) : (
          <H2>{value}</H2>
        )}
      </div>
      {subtitle && !loading && (
        <p className={Classes.TEXT_MUTED}>{subtitle}</p>
      )}
    </Card>
  );
}

