│   │   │   │   └── maintenance/
│   │   │   └── stores/
│   │   ├── e2e/                          # E2E tests (Playwright)
│   │   │   ├── pages/
│   │   │   │   ├── dashboard.spec.ts
│   │   │   │   ├── map.spec.ts
