class TestHaversineDistance:
    """Tests for haversine distance calculation"""

    def test_same_point_returns_zero(self):
        """Distance between same point should be zero"""
        result = haversine_distance(38.7223, -9.1393, 38.7223, -9.1393)
        assert result == 0.0

    def test_lisbon_to_porto(self):
        """Lisbon to Porto should be approximately 275-280 km"""
        # Lisbon coords
        lat1, lon1 = 38.7223, -9.1393
        # Porto coords
        lat2, lon2 = 41.1579, -8.6291

        result = haversine_distance(lat1, lon1, lat2, lon2)
        assert 270 < result < 285  # Approximate range

    def test_symmetric_distance(self):
        """Distance A->B should equal B->A"""
        dist_ab = haversine_distance(38.7223, -9.1393, 41.1579, -8.6291)
        dist_ba = haversine_distance(41.1579, -8.6291, 38.7223, -9.1393)
        assert dist_ab == pytest.approx(dist_ba)


class TestTrainAllocator:
